// rn-001: UI-thread swipe card with decay fling, hinged rotation, and accessible commit fallback
import React from 'react';
import {Pressable, Text, View, StyleSheet, useWindowDimensions} from 'react-native';
import {Gesture, GestureDetector} from 'react-native-gesture-handler';
import * as Haptics from 'expo-haptics';
import Animated, {
  Extrapolate,
  interpolate,
  runOnJS,
  useAnimatedStyle,
  useDerivedValue,
  useReducedMotion,
  useSharedValue,
  withDecay,
  withSpring,
} from 'react-native-reanimated';

export function SwipeToDismissCardStackWithRubberBandEdgesAndRotation({onCommit}: {onCommit: (dir: 'left' | 'right') => void}) {
  const {width} = useWindowDimensions();
  const cardWidth = Math.min(width - 32, 420);
  const reduceMotion = useReducedMotion();
  const x = useSharedValue(0);
  const y = useSharedValue(0);
  const nextScale = useDerivedValue(() => interpolate(Math.abs(x.value), [0, cardWidth * 0.35], [0.96, 1], Extrapolate.CLAMP));

  const commit = (dir: 'left' | 'right') => {
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
    onCommit(dir);
  };

  const pan = Gesture.Pan()
    .activeOffsetX([-10, 10])
    .failOffsetY([-22, 22])
    .onUpdate((event) => {
      const edge = cardWidth * 0.42;
      x.value = event.translationX / (1 + Math.max(0, Math.abs(event.translationX) - edge) / cardWidth);
      y.value = event.translationY * 0.35;
    })
    .onEnd((event) => {
      const shouldCommit = Math.abs(x.value) > cardWidth * 0.3 || Math.abs(event.velocityX) > 800;
      if (shouldCommit && !reduceMotion) {
        const dir = x.value > 0 ? 'right' : 'left';
        x.value = withDecay({velocity: event.velocityX, clamp: [-(cardWidth + 160), cardWidth + 160]});
        y.value = withDecay({velocity: event.velocityY * 0.25});
        runOnJS(commit)(dir);
        return;
      }
      x.value = reduceMotion ? 0 : withSpring(0, {damping: 15, stiffness: 180});
      y.value = reduceMotion ? 0 : withSpring(0, {damping: 15, stiffness: 180});
    });

  const cardStyle = useAnimatedStyle(() => {
    const rotate = interpolate(x.value, [-cardWidth, 0, cardWidth], [-15, 0, 15], Extrapolate.CLAMP);
    return {
      width: cardWidth,
      transform: [
        {translateX: x.value},
        {translateY: y.value},
        {translateY: cardWidth * 0.65},
        {rotateZ: `${rotate}deg`},
        {translateY: -cardWidth * 0.65},
      ],
    };
  });
  const nextStyle = useAnimatedStyle(() => ({transform: [{scale: nextScale.value}]}));

  return (
    <View style={styles.stack}>
      <Animated.View pointerEvents="none" style={[styles.card, styles.next, nextStyle]} />
      <GestureDetector gesture={pan}>
        <Animated.View style={[styles.card, cardStyle]}>
          <Pressable
            accessibilityRole="button"
            accessibilityLabel="Swipe card"
            accessibilityHint="Swipe left or right, or double tap to commit the top card."
            accessibilityActions={[{name: 'activate', label: 'Commit card'}]}
            onAccessibilityAction={() => commit('right')}
            onPress={() => commit('right')}
            hitSlop={8}
            style={styles.pressable}
          >
            <Text style={styles.title}>Swipe card</Text>
          </Pressable>
        </Animated.View>
      </GestureDetector>
    </View>
  );
}

const styles = StyleSheet.create({
  stack: {alignItems: 'center', justifyContent: 'center', minHeight: 420},
  card: {position: 'absolute', minHeight: 360, borderRadius: 20, backgroundColor: '#ffffff', shadowOpacity: 0.18, shadowRadius: 16, elevation: 8},
  next: {backgroundColor: '#e2e8f0'},
  pressable: {minHeight: 360, minWidth: 44, padding: 24, justifyContent: 'center'},
  title: {fontSize: 22, fontWeight: '700'},
});

// rn-002: in-tree three-snap bottom sheet with keyboard avoidance and accessible close path
import React, {useMemo} from 'react';
import {KeyboardAvoidingView, Platform, Pressable, ScrollView, StyleSheet, Text, useWindowDimensions, View} from 'react-native';
import {Gesture, GestureDetector} from 'react-native-gesture-handler';
import Animated, {Extrapolate, interpolate, useAnimatedStyle, useSharedValue, withSpring} from 'react-native-reanimated';
import {useSafeAreaInsets} from 'react-native-safe-area-context';

export function ThreeSnapPointBottomSheetFromScratchWithKeyboardAvoidance({open, onClose, children}: {open: boolean; onClose: () => void; children: React.ReactNode}) {
  const {height} = useWindowDimensions();
  const insets = useSafeAreaInsets();
  const snaps = useMemo(() => [height * 0.75, height * 0.4, height * 0.08], [height]);
  const y = useSharedValue(snaps[1]);
  const scrollY = useSharedValue(0);
  const startY = useSharedValue(snaps[1]);

  const snapTo = (target: number) => { y.value = withSpring(target, {damping: 18, stiffness: 200, mass: 0.8}); };
  const headerPan = Gesture.Pan()
    .onBegin(() => { startY.value = y.value; })
    .onUpdate((event) => { y.value = Math.max(snaps[2], Math.min(snaps[0], startY.value + event.translationY)); })
    .onEnd((event) => {
      const projected = y.value + event.velocityY * 0.2;
      const closest = snaps.reduce((best, snap) => Math.abs(snap - projected) < Math.abs(best - projected) ? snap : best, snaps[1]);
      snapTo(closest);
    });
  const bodyPan = Gesture.Pan()
    .onBegin(() => { startY.value = y.value; })
    .onUpdate((event) => {
      if (y.value <= snaps[2] + 4 && scrollY.value > 0) return;
      if (event.translationY > 0) y.value = Math.min(snaps[0], startY.value + event.translationY);
    })
    .onEnd((event) => {
      if (event.translationY > 0) snapTo(Math.abs(event.velocityY) > 900 ? snaps[0] : snaps[1]);
    });

  const sheetStyle = useAnimatedStyle(() => ({transform: [{translateY: y.value}]}));
  const backdropStyle = useAnimatedStyle(() => ({opacity: interpolate(y.value, [snaps[0], snaps[2]], [0, 0.5], Extrapolate.CLAMP)}));
  if (!open) return null;

  return (
    <View style={StyleSheet.absoluteFill} pointerEvents="box-none">
      <Animated.View style={[StyleSheet.absoluteFill, styles.backdrop, backdropStyle]} />
      <Pressable accessibilityRole="button" accessibilityLabel="Close sheet" style={StyleSheet.absoluteFill} onPress={onClose} />
      <KeyboardAvoidingView behavior={Platform.OS === 'ios' ? 'padding' : undefined} style={StyleSheet.absoluteFill} pointerEvents="box-none">
        <GestureDetector gesture={headerPan}>
          <Animated.View accessibilityRole="dialog" accessibilityViewIsModal accessibilityLabel="Bottom sheet" style={[styles.sheet, {paddingBottom: insets.bottom + 16}, sheetStyle]}>
            <View style={styles.handle} />
            <Pressable accessibilityRole="button" accessibilityLabel="Close bottom sheet" hitSlop={8} style={styles.close} onPress={onClose}><Text>Close</Text></Pressable>
            <GestureDetector gesture={bodyPan}>
              <ScrollView
                keyboardShouldPersistTaps="handled"
                onScroll={(event) => { scrollY.value = event.nativeEvent.contentOffset.y; }}
                scrollEventThrottle={16}
                contentContainerStyle={styles.content}
              >
                {children}
              </ScrollView>
            </GestureDetector>
          </Animated.View>
        </GestureDetector>
      </KeyboardAvoidingView>
    </View>
  );
}

const styles = StyleSheet.create({
  backdrop: {backgroundColor: '#000'},
  sheet: {position: 'absolute', left: 0, right: 0, bottom: 0, minHeight: '92%', borderTopLeftRadius: 24, borderTopRightRadius: 24, backgroundColor: '#fff', shadowOpacity: 0.2, shadowRadius: 20, elevation: 24},
  handle: {alignSelf: 'center', width: 36, height: 4, borderRadius: 2, backgroundColor: '#94a3b8', marginTop: 8},
  close: {minHeight: 44, minWidth: 44, alignSelf: 'flex-end', alignItems: 'center', justifyContent: 'center', paddingHorizontal: 12},
  content: {padding: 16, paddingBottom: 48},
});

