const {width: SW} = Dimensions.get('window');
const W = Math.min(320, SW - 32); const H = 56; const R_RECT = 28; const R_CIRC = 28;
type State = 'idle'|'loading'|'success'|'error';
type Props = {onSubmit: () => Promise<boolean>; label?: string};

export function MorphButton({onSubmit, label='Confirm payment'}: Props) {
  const [state, setState] = useState<State>('idle');
  const p = useSharedValue(0); const press = useSharedValue(1); const rot = useSharedValue(0); const shake = useSharedValue(0); const check = useSharedValue(0);
  useEffect(() => { if (state === 'loading') { rot.value = withRepeat(withTiming(360, {duration: 900, easing: Easing.linear}), -1, false); } else { rot.value = 0; } }, [state]);
  const handle = async () => { if (state === 'loading' || state === 'success') return; setState('loading'); p.value = withTiming(1, {duration: 300, easing: Easing.bezier(0.4, 0, 0.2, 1)}); const ok = await onSubmit(); if (ok) { setState('success'); p.value = withTiming(2, {duration: 240}); check.value = withTiming(1, {duration: 360, easing: Easing.bezier(0.4, 0, 0.2, 1)}); Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success); } else { setState('error'); Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error); shake.value = withSequence(withTiming(-6, {duration:50}), withTiming(6, {duration:50}), withTiming(-4, {duration:50}), withTiming(4, {duration:50}), withTiming(0, {duration:50})); p.value = withTiming(0, {duration: 280}); setTimeout(() => setState('idle'), 600); }};
  const containerStyle = useAnimatedStyle(() => ({width: interpolate(p.value, [0, 1, 2], [W, H, H], Extrapolation.CLAMP), height: H, borderRadius: interpolate(p.value, [0, 1, 2], [R_RECT, R_CIRC, R_CIRC]), backgroundColor: interpolateColor(p.value, [0, 1, 2], ['#0A84FF', '#0A84FF', '#30D158']), transform: [{translateX: shake.value}, {scale: press.value}]}));
  const textStyle = useAnimatedStyle(() => ({opacity: interpolate(p.value, [0, 0.4], [1, 0], Extrapolation.CLAMP)}));
  const spinnerStyle = useAnimatedStyle(() => ({opacity: interpolate(p.value, [0.6, 1, 1.4], [0, 1, 0], Extrapolation.CLAMP), transform: [{rotate: `${rot.value}deg`}]}));
  const checkStyle = useAnimatedStyle(() => ({opacity: interpolate(p.value, [1.6, 2], [0, 1], Extrapolation.CLAMP)}));
  const checkLine1 = useAnimatedStyle(() => ({width: interpolate(check.value, [0, 0.5, 1], [0, 10, 10])}));
  const checkLine2 = useAnimatedStyle(() => ({width: interpolate(check.value, [0.5, 1], [0, 16])}));
  return (<Pressable disabled={state==='loading' || state==='success'} onPressIn={() => { press.value = withTiming(0.97, {duration: 80}); }} onPressOut={() => { press.value = withTiming(1, {duration: 120}); }} onPress={handle} accessibilityRole='button' accessibilityLabel={label} accessibilityState={{busy: state==='loading', disabled: state==='loading'}}><Animated.View style={[s.btn, containerStyle]}><Animated.Text style={[s.label, textStyle]}>{state==='error' ? 'Try again' : label}</Animated.Text><Animated.View style={[s.spinner, spinnerStyle]}/><Animated.View style={[s.check, checkStyle]}><Animated.View style={[s.checkSegment, s.checkSeg1, checkLine1]}/><Animated.View style={[s.checkSegment, s.checkSeg2, checkLine2]}/></Animated.View></Animated.View></Pressable>);
}
