const PAD = 16;

export function RobinhoodStyleLineChartWithScrubbingCrosshair({data}: {data: Point[]}) {
  const points = data.length ? data : [
    {time: '09:30', price: 101}, {time: '10:00', price: 103}, {time: '10:30', price: 99},
    {time: '11:00', price: 108}, {time: '11:30', price: 106},
