  const path = useMemo(() => {
    const prices = points.map((p) => p.price);
    const min = Math.min(...prices);
    const max = Math.max(...prices);
    const scaleY = (price: number) => HEIGHT - PAD - ((price - min) / Math.max(1, max - min)) * (HEIGHT - PAD * 2);
